from typing import List

MOD = 10**9 + 7

class Solution:
    def sumOfPower(self, nums: List[int], k: int) -> int:
        n = len(nums)
        dp = [0] * (k + 1)
        dp[0] = 1  # Base case: one way to make sum 0 (take nothing)

        for num in nums:
            for i in range(k, num - 1, -1):
                dp[i] = (dp[i] + dp[i - num]) % MOD

        return dp[k]
